import{_ as t,C as e,o as s,c as a,H as r,Q as c}from"./chunks/framework.e5b03845.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"growth/readbook.md","filePath":"growth/readbook.md"}'),p={name:"growth/readbook.md"},n=c('<div class="tip custom-block"><p class="custom-block-title">今日话题：</p><p><strong>我们该如何看书呢？</strong></p></div><p>我看书的秘诀，就是“<strong>心领神会</strong>”这四个字。</p><p>看书是用眼来看，用心去体会，正如，葛仙翁所说：“诵持万遍，妙理自明”。这里的“诵持万遍”，不是说你把《清静经》读一万遍、或者背一万遍，就能懂了。</p><p>而是，根据书中给你的启示，行动起来。在行动的过程中，不断地问自己：“<strong>你心里明白了没有？你心里知道了没有？</strong>”</p><p>因为，只有自己心里明白了、知道了，内里的<code>元神</code>才能知晓，这里的元神就相当于现代心理学中的潜意识。下次，当我们遇到事儿的时候，只要心念一动，内里的元神就会指挥着我们的身体，去完成心里所想。</p><p>这便是我看书的方法，学习亦然。</p><div class="danger custom-block"><p class="custom-block-title">延展思考：</p><p>你觉得“心领神会” VS “一万小时定律”，哪个学习理念更加适合你呢？</p></div>',7);function _(d,l,i,m,g,k){const o=e("PageHeader");return s(),a("div",null,[r(o,{content:"我们该如何看书呢？"}),n])}const f=t(p,[["render",_]]);export{b as __pageData,f as default};
